  ('police-8b7f1efc-moex-00399', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '第一線警察工作實務人員規劃犯罪預防活動時，可採取問題導向警政策略中之SARA模式，有關 SARA內涵之敘述，下列何者錯誤？', '["掃描檢視（Scanning）", "處理能力（Ability）", "回應策略（Response）", "評估成效（Assessment）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00400', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關美國梅根法案（Megan''sLaw）的敘述，下列何者錯誤？', '["法案名稱來自一個遭性侵害並被殺害的女童", "該女童係於2004年遭有性侵害前科的男子性侵並遭殺害", "法案規定美國各州必須建立性罪犯和騷擾兒童罪犯的檔案", "法案規定各州必須將有性侵兒童前科者的個人資料公開在網際網路上供民眾查詢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00401', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '犯罪預防由公共醫療模式角度可區分為三個層次：初級、次級與三級預防。針對不同對象的三級 犯罪預防措施，下列敘述何者錯誤？', '["犯罪預防宣導是屬於被害者導向的初級預防措施", "中輟少年輔導是屬於加害者導向的次級預防措施", "犯罪者矯正計畫是屬於加害者導向的三級預防措施", "酒吧內暴力預防是屬於社區導向的三級預防措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00402', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '根據 Dunn（2008）主張，警政問題分類可以用參與決策制定者的多寡、政策方案數、效用價值 共識度、方案風險高低、結果發生機率等面向作為標準，界定問題類型結構之良窳。下列敘述何 者錯誤？', '["結構良好的警政問題，方案後果確定", "結構良好的警政問題，發生機率無法計算", "結構不良的警政問題，政策決定者很多", "結構不良的警政問題，效用價值衝突"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00403', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警察政策分析專家身負警政規劃重任，應具備政策專家應有的德行。有關警察政策分析專家倫理， 下列敘述何者錯誤？', '["警察人員在規劃政策時，要避免政策分析受到個人私利影響", "警察人員在規劃政策時，應以文獻資料為依據", "警察人員在擬定政策時，若涉及價值的取捨時，應說明其取捨之理由", "警察人員在擬定政策過程，應鼓勵民眾參與，以提升警察工作的可行性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00404', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關犯罪被害成因的文獻資料，下列敘述何者錯誤？', '["德國學者HansVonHentig（1948）主張，「許多犯罪被害者係因本身因素而成為被害人」", "美國學者SchaferStephen（1968）認為，被害者對「犯罪之發生」（genesisofcrime）應負責任", "美國學者MarvinWolfgang（1958）提出「被害者促發」（VictimPrecipitation）的概念", "在加拿大學者GartnerandMccarthy（1991）研究發現，「婦女經濟權力提高了被害風險」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00405', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Felson和Clarke（1998）主張，新機會理論（NewOpportunityTheories）是由三個理論所構成， 這些理論以不同的方式說明「機會」的概念，下列何者不是該三個理論之一？', '["日常活動理論（RoutineActivityTheory）", "犯罪型態理論（CrimePatternTheory）", "理性選擇理論（RationalChoiceTheory）", "生活型態理論（Life-StyleTheory）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00406', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '社區導向警政（Community-oriented policing）具體的操作方式是CAMP，有關CAMP的敘述， 下列何者錯誤？', '["C係指比較問題（Comparingproblem）", "A係指調整警察組織的勤務運作回應社區（Adapting）", "M係指動員社區志工及團體的資源（Mobilizing）", "P係指問題解決（Problemsolving）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
